// Extract email metadata for classification
const items = [];

for (const item of $input.all()) {
  const email = item.json;

  // Extract sender — IMAP node provides from as object or string
  let sender = 'unknown';
  let senderEmail = 'unknown';
  if (email.from) {
    if (typeof email.from === 'string') {
      sender = email.from;
      // Try to extract email from angle brackets
      const emailMatch = email.from.match(/<([^>]+)>/);
      senderEmail = emailMatch ? emailMatch[1] : email.from;
    } else if (email.from.value && email.from.value[0]) {
      sender = email.from.value[0].name
        ? `${email.from.value[0].name} <${email.from.value[0].address}>`
        : email.from.value[0].address;
      senderEmail = email.from.value[0].address;
    } else if (email.from.text) {
      sender = email.from.text;
      const emailMatch = email.from.text.match(/<([^>]+)>/);
      senderEmail = emailMatch ? emailMatch[1] : email.from.text;
    }
  }

  // Extract subject
  const subject = email.subject || '(no subject)';

  // Extract date
  const date = email.date || email.receivedAt || new Date().toISOString();

  // Extract body snippet — first 500 chars
  let bodySnippet = '';
  if (email.text) {
    bodySnippet = email.text.substring(0, 500);
  } else if (email.html) {
    // Strip HTML tags for a readable snippet
    bodySnippet = email.html
      .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
      .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
      .replace(/<[^>]+>/g, ' ')
      .replace(/\s+/g, ' ')
      .trim()
      .substring(0, 500);
  } else if (email.textPlain) {
    bodySnippet = email.textPlain.substring(0, 500);
  }

  // Preserve the original message UID/ID for IMAP operations
  const messageId = email.messageId || email.uid || '';

  items.push({
    json: {
      messageId,
      sender,
      senderEmail,
      subject,
      date,
      bodySnippet
    }
  });
}

return items;

