// Parse the LLM classification response
const items = [];

for (const item of $input.all()) {
  const llmResponse = item.json;

  // Get original email metadata from the Extract node
  const emailMeta = $('Extract Email Metadata').item.json;

  let classification;
  try {
    const content = llmResponse.choices[0].message.content;
    // Handle both string and pre-parsed JSON
    if (typeof content === 'string') {
      // Strip markdown code fences if present
      const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
      classification = JSON.parse(cleaned);
    } else {
      classification = content;
    }
  } catch (e) {
    // Fallback classification on parse error
    classification = {
      category: 'Personal',
      priority: 3,
      action: 'review',
      confidence: 0.0,
      summary: 'Classification parse error: ' + e.message
    };
  }

  // Normalize priority to integer 1-5
  let priority = parseInt(classification.priority, 10);
  if (isNaN(priority) || priority < 1) priority = 1;
  if (priority > 5) priority = 5;

  // Normalize confidence to float 0.0-1.0
  let confidence = parseFloat(classification.confidence);
  if (isNaN(confidence)) confidence = 0.0;
  if (confidence < 0) confidence = 0.0;
  if (confidence > 1) confidence = 1.0;

  items.push({
    json: {
      // Original email fields
      messageId: emailMeta.messageId,
      sender: emailMeta.sender,
      senderEmail: emailMeta.senderEmail,
      subject: emailMeta.subject,
      date: emailMeta.date,
      // Classification fields
      category: classification.category || 'Personal',
      priority,
      action: classification.action || 'review',
      confidence,
      summary: classification.summary || ''
    }
  });
}

return items;

// Alternative archive approach: use an HTTP Request to Fastmail JMAP
// to mark specific messages as read, since n8n's IMAP node doesn't
// support marking individual messages by UID.
//
// This Code node logs the archive action. In production, replace with
// a JMAP Email/set call or an IMAP STORE command via a custom function.
//
// For now, log the emails that should be archived.
const items = [];

for (const item of $input.all()) {
  const email = item.json;
  console.log(`[ARCHIVE] Marking as read: "${email.subject}" from ${email.sender} (priority: ${email.priority}, category: ${email.category})`);
  items.push({
    json: {
      ...email,
      archived: true,
      archivedAt: new Date().toISOString()
    }
  });
}

return items;
